---@type H5vPluginModule
return { health = function(ctx) return { status = ctx.health.healthy, summary = "ready", message = ctx.ui.build(function(ui) ui.text("🟢 successfully loaded plugin") end), } end, init = function(h5v, ctx) ctx.toast.info("success :D") end,
}

116.body:
Examples: h5v.commands.register({ id = "analysis.refresh", title = "Refresh analysis", summary = "Refresh plugin output", run = function(ctx) ctx.toast.info("refreshing") end,
}) h5v.events.on({ event = h5v.ids.events.file_opened, run = function(ctx) ctx.log.info("opened " .. ctx.event.path) end,
}) h5v.mchart.functions.register({ id = "analysis.scale", name = "scale", params = { { name = "series", kind = h5v.ids.value_kinds.series }, { name = "factor", kind = h5v.ids.value_kinds.scalar }, }, returns = h5v.ids.value_kinds.series, eval = function(series, factor) return series * factor end,
}) Plugins can also use: ctx.process.run(...) ctx.process.parse_json(...) ctx.toast.*(...) ctx.log.*(...) ctx.ui.build(...)

